from flask import Flask, request, jsonify
import pymemcache.client.base as memcache_client

app = Flask(__name__)
client = memcache_client.Client(('127.0.0.1', 11211), connect_timeout=1.0, socket_timeout=3.0)

# Dummy database function
def get_data_from_database(key):
    return f"Data for {key}"

@app.route('/data/<key>', methods=['GET'])
def get_data(key):
    ttl = 60  # Cache TTL in seconds

    cached_data = client.get(key)
    if cached_data is None:
        data = get_data_from_database(key)
        client.set(key, data, expire=ttl)
    else:
        data = cached_data.decode('utf-8')

    return jsonify({'key': key, 'data': data})

if __name__ == '__main__':
    app.run(debug=True)